          <div className="flex justify-center">
            <button 
              disabled={!tempOption || isTransitioning}
              onClick={() => handleNext()}
              className={`px-24 py-7 rounded-full font-black uppercase tracking-[0.2em] text-[11px] transition-all shadow-xl ${tempOption ? 'bg-charcoal text-white hover:bg-black scale-100' : 'bg-slate-100 text-slate-300 scale-95 cursor-not-allowed'}`}
