import { Question, Submission, ResponseIndicator, WellBeingLevel } from '../types';
import { QUIZ_DATA } from '../constants';
import { GoogleGenAI } from "@google/genai";
import { supabase } from './supabase';

const QUESTIONS_KEY = 'nit_gyanam_questions_v2';
const SUBMISSIONS_KEY = 'nit_gyanam_submissions_v2';

export const api = {
  fetchQuestions: async (): Promise<Question[]> => {
    // 1. Try cloud
    if (supabase) {
      const { data, error } = await supabase.from('questions').select('*');
      if (!error && data && data.length > 0) return data;
    }

    // 2. Fallback to Local
    const saved = localStorage.getItem(QUESTIONS_KEY);
    if (!saved) {
      localStorage.setItem(QUESTIONS_KEY, JSON.stringify(QUIZ_DATA));
      return QUIZ_DATA;
    }
    return JSON.parse(saved);
  },

  saveQuestions: async (questions: Question[]) => {
    // 1. Save to Cloud
    if (supabase) {
      await supabase.from('questions').upsert(questions);
    }
    // 2. Always backup to Local
    localStorage.setItem(QUESTIONS_KEY, JSON.stringify(questions));
  },

  submitAssessment: async (submission: Submission) => {
    // 1. Submit to Cloud
    if (supabase) {
      try {
        const dbSubmission = {
          id: submission.id,
          student_name: submission.student.name,
          student_age: submission.student.age,
          student_standard: submission.student.standard,
          student_school: submission.student.school,
          level: submission.level,
          answers: submission.answers,
          risk_status: submission.riskStatus,
          conclusion: submission.conclusion,
          ai_report: submission.aiReport,
          timestamp: submission.timestamp
        };
        const { error } = await supabase.from('submissions').insert([dbSubmission]);
        if (error) console.warn("Supabase Sync Failed:", error);
      } catch (e) {
        console.error("Cloud DB Error:", e);
      }
    }

    // 2. Local Persistence
    const saved = localStorage.getItem(SUBMISSIONS_KEY);
    const submissions: Submission[] = saved ? JSON.parse(saved) : [];
    submissions.unshift(submission);
    localStorage.setItem(SUBMISSIONS_KEY, JSON.stringify(submissions));

    return submission;
  },

  fetchSubmissions: async (): Promise<Submission[]> => {
    // 1. Fetch from Cloud
    if (supabase) {
      const { data, error } = await supabase
        .from('submissions')
        .select('*')
        .order('timestamp', { ascending: false });

      if (!error && data) {
        return data.map(d => ({
          id: d.id,
          student: {
            name: d.student_name,
            age: d.student_age,
            standard: d.student_standard,
            school: d.student_school
          },
          level: d.level,
          answers: d.answers,
          riskStatus: d.risk_status,
          conclusion: d.conclusion,
          aiReport: d.ai_report,
          timestamp: d.timestamp,
          metrics: {
            totalQuestions: Object.keys(d.answers || {}).length,
            healthyCount: 0, concernCount: 0, redFlagCount: 0 
          }
        }));
      }
    }

    // 2. Fallback to Local
    const saved = localStorage.getItem(SUBMISSIONS_KEY);
    return saved ? JSON.parse(saved) : [];
  },

  generateAIAnalysis: async (submission: Submission, questions: Question[]): Promise<string> => {
    // Validate API Key
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      return "AI Analysis Error: Gemini API Key is missing. Please check your environment configuration.";
    }

    const ai = new GoogleGenAI({ apiKey });

    // Constructing a detailed summary for the AI
    const answerEntries = Object.entries(submission.answers || {});
    if (answerEntries.length === 0) {
      return "No diagnostic data available for AI synthesis.";
    }

    const answerSummary = answerEntries.map(([qid, ans]: [string, any]) => {
      const q = questions.find(q => q.id === qid);
      if (!q) return `- Unknown Question (ID: ${qid}): Status ${ans.indicator || 'N/A'}`;
      const opt = q.options.find(o => o.id === ans.optionId);
      return `- **Q: ${q.textEn}**\n  Selected: "${opt?.en || 'N/A'}"\n  Indicator: ${ans.indicator || 'N/A'}`;
    }).join('\n\n');

    const profileContext = `
      STUDENT PROFILE:
      Name: ${submission.student.name}
      Age: ${submission.student.age}
      Academic Standard: ${submission.student.standard}
      Level Category: ${submission.level}
      Calculated Risk Status: ${submission.riskStatus}
    `;

    const promptText = `
      Perform a professional clinical synthesis for the following student assessment data:

      ${profileContext}

      DETAILED RESPONSES:
      ${answerSummary}
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: promptText }] }],
        config: {
          systemInstruction: "You are a world-class Senior Clinical Child Psychologist. Your task is to analyze student well-being assessments. Provide a structured report in 3 sections: 1. BEHAVIORAL SYNTHESIS (Analyze patterns in their choices), 2. CLINICAL CLASSIFICATION (Justify why they are STABLE, MODERATE, or CRITICAL), 3. ACTIONABLE INTERVENTION STRATEGY (Specific advice for teachers/parents). Maintain a professional, empathetic, and clinical tone. End with a legal medical disclaimer.",
          temperature: 0.7,
          topK: 40,
          topP: 0.95,
        }
      });

      return response.text || "Report generation returned an empty result. Please review data manually.";
    } catch (error: any) {
      console.error("AI Analysis Execution Error:", error);
      return `Clinical Synthesis failed due to a technical error: ${error.message || 'Unknown API Error'}. Please ensure the Gemini API Key is valid and safety filters are not being triggered.`;
    }
  },

  analyzeResults: (answers: ResponseIndicator[]) => {
    const total = answers.length;
    if (total === 0) return { riskStatus: 'STABLE' as const, conclusion: 'No data to analyze.' };

    const redFlagCount = answers.filter(a => a === ResponseIndicator.RED_FLAG).length;
    const concernCount = answers.filter(a => a === ResponseIndicator.CONCERN).length;
    const healthyCount = answers.filter(a => a === ResponseIndicator.HEALTHY).length;

    const redFlagPct = (redFlagCount / total) * 100;

    if (redFlagPct >= 10) {
      return {
        riskStatus: 'CRITICAL' as const,
        conclusion: 'URGENT INTERVENTION REQUIRED. High-risk psychological markers detected in the student\'s profile.'
      };
    } else if (concernCount > healthyCount || concernCount > (total * 0.3)) {
      return {
        riskStatus: 'MODERATE' as const,
        conclusion: 'MODERATE STRESS DETECTED. Patterns of anxiety or emotional fatigue identified. Recommend secondary screening.'
      };
    } else {
      return {
        riskStatus: 'STABLE' as const,
        conclusion: 'STUDENT APPEARS STABLE. Healthy adjustment markers and positive outlook noted.'
      };
    }
  }
};

