  },

  fetchSubmissions: async (): Promise<Submission[]> => {
    if (supabase) {
      const { data, error } = await supabase
        .from('submissions')
        .select('*')
        .order('timestamp', { ascending: false });
      if (!error && data) {
        return data.map(d => ({
