    const promptText = `
      NITGYANAM CLINICAL ASSESSMENT REPORT
      ------------------------------------
      Patient Name: ${submission.student.name}
      Education Level: ${submission.student.standard}
      Initial System Risk: ${submission.riskStatus}

      BEHAVIORAL DATA POINTS:
      ${answerSummary}

      REQUIRED CLINICAL SYNTHESIS FORMAT:
      1. CLINICAL OVERVIEW: Brief summary of the student's psychological profile.
      2. RISK IDENTIFICATION: Detailed analysis of RED_FLAG or CONCERN markers.
