    const total = answers.length;
    if (total === 0) return { riskStatus: 'STABLE' as const, conclusion: 'No data.' };
    const redFlagCount = answers.filter(a => a === ResponseIndicator.RED_FLAG).length;
    const concernCount = answers.filter(a => a === ResponseIndicator.CONCERN).length;

    const redFlagPct = (redFlagCount / total) * 100;

    if (redFlagPct >= 10 || redFlagCount >= 2) return { riskStatus: 'CRITICAL' as const, conclusion: 'Immediate clinical review recommended.' };
    if (concernCount > (total * 0.25)) return { riskStatus: 'MODERATE' as const, conclusion: 'Sub-clinical stress detected. Active monitoring required.' };

    return { riskStatus: 'STABLE' as const, conclusion: 'Psychological baseline appears healthy.' };
  }
};

